import chalk from 'chalk';
import { parse } from 'yaml';

interface SchemaSection {
  glob?: string;
  files?: string[];
  namespaces?: Record<string, string[]>;
}

interface AppManifest {
  app: string;
  version: string;
  schemas: Record<string, SchemaSection>;
}

function collectManifestFiles(section: SchemaSection): string[] {
  const files: string[] = [];
  if (section.files) files.push(...section.files);
  if (section.namespaces) {
    for (const nsFiles of Object.values(section.namespaces)) {
      files.push(...nsFiles);
    }
  }
  return files;
}

function globFiles(pattern: string, projectRoot: string): string[] {
  // Simple glob: supports *.ext and **/*.ext patterns
  const parts = pattern.split('/');
  const ext = parts[parts.length - 1].replace('*', '');
  const starStarIdx = parts.indexOf('**');

  if (starStarIdx === -1) {
    const dir = resolve(projectRoot, parts.slice(0, -1).join('/'));
    if (!existsSync(dir)) return [];
    return readdirSync(dir)
      .filter(f => f.endsWith(ext))
      .map(f => join(parts.slice(0, -1).join('/'), f));
  }

  // Recursive glob (** pattern)
  const baseDir = resolve(projectRoot, parts.slice(0, starStarIdx).join('/'));
  const results: string[] = [];

  function walkDir(dir: string, relBase: string): void {
    if (!existsSync(dir)) return;
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      if (entry.isDirectory() && !entry.name.startsWith('_')) {
        walkDir(join(dir, entry.name), join(relBase, entry.name));
      } else if (entry.isFile() && entry.name.endsWith(ext) && !entry.name.startsWith('_')) {
        results.push(join(relBase, entry.name));
      }
    }
  }

  walkDir(baseDir, parts.slice(0, starStarIdx).join('/'));
  return results;
}

export const validateManifestCommand = new Command('validate-manifest')
  .description('Validate app.flusk.yaml against schema files on disk')
  .option('--fix-orphans', 'Report orphaned schemas (on disk but not in manifest)')
  .action(async (options) => {
    const projectRoot = process.cwd();
    const manifestPath = resolve(projectRoot, 'app.flusk.yaml');

    if (!existsSync(manifestPath)) {
      console.error(chalk.red('❌  app.flusk.yaml not found'));
      process.exit(1);
    }

    const raw = readFileSync(manifestPath, 'utf-8');
    const manifest = parse(raw) as AppManifest;

    console.log(chalk.blue(`\n🔍 Validating manifest: ${manifest.app} v${manifest.version}\n`));

    let hasErrors = false;

    for (const [sectionName, section] of Object.entries(manifest.schemas)) {
      const manifestFiles = new Set(collectManifestFiles(section));
      const diskFiles = section.glob ? new Set(globFiles(section.glob, projectRoot)) : new Set<string>();

      const missing: string[] = [...manifestFiles].filter(f => !existsSync(resolve(projectRoot, f)));
      const orphaned: string[] = [...diskFiles].filter(f => !manifestFiles.has(f));

      if (missing.length === 0 && orphaned.length === 0) {
        console.log(chalk.green(`  ✅ ${sectionName} — ${manifestFiles.size} files OK`));
        continue;
      }

      console.log(chalk.yellow(`  ⚠️  ${sectionName}:`));

      for (const f of missing) {
        console.log(chalk.red(`     ❌ MISSING: ${f}`));
        hasErrors = true;
      }

      for (const f of orphaned) {
        const prefix = options.fixOrphans ? '❓ ORPHANED' : '⚪ ORPHANED';
        console.log(chalk.gray(`     ${prefix}: ${f}`));
      }
    }

    console.log('');
    if (hasErrors) {
      console.log(chalk.red('❌  Manifest validation failed — missing schema files\n'));
      process.exit(1);
    } else {
      console.log(chalk.green('✅  Manifest is valid\n'));
    }
  });
